9|/** 项目指令加载器（F1, F7, F8）。三层路径顺序加载并拼接。 */
10|public final class InstructionLoader {
11|    private static volatile String cached;
12|
13|    private InstructionLoader() {}
14|
15|    /** 按三层顺序加载并拼接（F1）。结果缓存（F8）。 */
16|    public static String load(Path projectRoot) {
17|        if (cached != null) return cached;
18|        StringBuilder sb = new StringBuilder();
19|        Path home = Path.of(System.getProperty("user.home", ""));
20|
21|        // ① 项目根 EasyCode.md（最高优先级）
22|        Path easyCode = projectRoot.resolve("EasyCode.md");
23|        Path codex = projectRoot.resolve("CODEX.md");
24|        appendIfExists(sb, Files.isRegularFile(easyCode) ? easyCode : codex, projectRoot, projectRoot);
25|        // ② .easycode/EasyCode.md
26|        appendIfExists(sb, projectRoot.resolve(".easycode/EasyCode.md"), projectRoot, projectRoot);
27|        // ③ ~/.easycode/EasyCode.md（最低优先级）
28|        appendIfExists(sb, home.resolve(".easycode/EasyCode.md"), home.resolve(".easycode"), home.resolve(".easycode"));
29|
30|        cached = sb.toString().trim();
31|        return cached;
32|    }
33|
34|    private static void appendIfExists(StringBuilder sb, Path file, Path baseDir, Path rootBoundary) {
35|        if (!Files.isRegularFile(file)) return;
36|        try {
37|            String raw = Files.readString(file, StandardCharsets.UTF_8);
38|            String expanded = IncludeResolver.resolve(raw, baseDir, rootBoundary, 1, new HashSet<>());
39|            if (!expanded.isBlank()) {
40|                if (sb.length() > 0) sb.append("\n\n");
41|                sb.append(expanded);
42|            }
43|        } catch (IOException e) {
44|            // 静默跳过（F6）
45|        }
46|    }
47|
48|    /** 清除缓存（测试用） */
49|    static void clearCache() { cached = null; }
