1|package com.easycode.instructions;
2|
3|import java.io.IOException;
4|import java.nio.charset.StandardCharsets;
5|import java.nio.file.Files;
6|import java.nio.file.Path;
7|import java.util.Set;
8|import java.util.regex.Pattern;
9|
10|/** @include 展开引擎（F2-F6）。递归解析 @include 指令，处理嵌套深度/环路/逃逸。 */
11|final class IncludeResolver {
12|    private static final int MAX_DEPTH = 5;
13|    private static final Pattern INCLUDE_LINE = Pattern.compile("^@include\\s+(.+)$");
14|
15|    private IncludeResolver() {}
16|
17|    /**
18|     * @param content      源内容
19|     * @param baseDir      当前文件所在目录
20|     * @param rootBoundary 安全边界（项目级=projectRoot，用户级=~/.easycode/）
21|     * @param depth        当前深度（1=原始文件）
22|     * @param visited      已访问的规范绝对路径集合
23|     */
24|    static String resolve(String content, Path baseDir, Path rootBoundary,
25|                          int depth, Set<String> visited) {
26|        StringBuilder result = new StringBuilder();
27|        for (String line : content.split("\n", -1)) {
28|            String trimmed = line.trim();
29|            var matcher = INCLUDE_LINE.matcher(trimmed);
30|            // F2: 独占一行的 @include 才展开
31|            if (matcher.matches() && trimmed.equals(line.trim())) {
32|                String relPath = matcher.group(1).trim();
33|                String expanded = expandInclude(relPath, baseDir, rootBoundary, depth, visited);
34|                if (expanded.startsWith("<!--")) {
35|                    result.append(expanded).append('\n');
36|                } else {
37|                    result.append(expanded);
38|                }
39|            } else {
40|                result.append(line).append('\n');
41|            }
42|        }
43|        return result.toString();
44|    }
45|
46|    private static String expandInclude(String relPath, Path baseDir, Path rootBoundary,
47|                                        int depth, Set<String> visited) {
48|        if (depth >= MAX_DEPTH) {
49|            return "<!-- @include 超过最大嵌套深度，已跳过: " + relPath + " -->";
50|        }
51|        try {
52|            Path resolved = baseDir.resolve(relPath).normalize().toRealPath();
53|            // F5: 路径逃逸检测
54|            if (!resolved.startsWith(rootBoundary.toRealPath())) {
55|                return "<!-- @include 路径超出允许范围，已跳过: " + relPath + " -->";
56|            }
57|            // F4: 环路检测
58|            String absKey = resolved.toString();
59|            if (!visited.add(absKey)) {
60|                return "<!-- @include 检测到环路，已跳过: " + relPath + " -->";
61|            }
62|            // F6: 二进制检测
63|            byte[] head = new byte[512];
64|            try (var is = Files.newInputStream(resolved)) {
65|                int n = is.read(head);
66|                for (int i = 0; i < n; i++) {
67|                    if (head[i] == 0) return "<!-- @include 二进制文件，已跳过: " + relPath + " -->";
68|                }
69|            }
70|            String fileContent = Files.readString(resolved, StandardCharsets.UTF_8);
71|            return resolve(fileContent, resolved.getParent(), rootBoundary, depth + 1, visited);
72|        } catch (IOException e) {
73|            // F6: 文件不存在/不可读，静默跳过
74|            return "<!-- @include 文件无法读取，已跳过: " + relPath + " -->";
75|        }
76|    }
