9|/** 模块化系统提示装配器 */
10|public final class Prompt {
11|
12|    private Prompt() {}
13|
14|    /** 七个固定模块，按 priority 升序（值越小越靠前） */
15|    public static List<Module> fixedModules() {
16|        return List.of(
17|            new Module("身份", 10, "你是 EasyCode，一个终端 AI 编程助手。"),
18|            new Module("系统约束", 20,
19|                "路径统一用正斜杠 /。用户要求模糊时反问确认。工具结果截断时用 offset 继续读。"),
20|            new Module("任务模式", 30, ""),
21|            new Module("动作执行", 40,
22|                "优先凭自身知识回答；需要准确文件内容、项目结构或代码细节时再使用工具。"),
23|            new Module("工具使用", 50,
24|                "编辑文件前必须先 read_file 读取；优先用专用工具(read_file/find_files/grep_code)而非 exec_command 拼凑 shell。"),
25|            new Module("语气风格", 60, "用中文回答，简洁直接。"),
26|            new Module("文本输出", 70, "每次回答必须以文字形式给出结论，不允许只调工具不说话。")
27|        );
28|    }
29|
30|    /** 三个可选空槽，留待后续章节填充 */
31|    public static List<Module> optionalModules() {
32|        return List.of(
33|            new Module("自定义指令", 80, ""),
34|            new Module("已激活 Skill", 90, ""),
35|            new Module("长期记忆", 100, "")
36|        );
37|    }
38|
39|    /** 按 priority 升序排列，跳过 content 为空的模块，以 "\n\n" 连接 */
40|    public static String assemble(List<Module> modules) {
41|        return modules.stream()
42|            .filter(m -> !m.content().isEmpty())
43|            .sorted(Comparator.comparingInt(Module::priority))
44|            .map(Module::content)
45|            .collect(Collectors.joining("\n\n"));
46|    }
47|
48|    /** 构建稳定系统提示（固定模块 + 可选模块，不含环境信息） */
49|    public static String buildStable() { return buildSystemPrompt("", ""); }
50|    public static String buildSystemPrompt(String instructions, String memory) {
51|        List<Module> all = new ArrayList<>();
52|        all.addAll(fixedModules());
53|        all.addAll(optionalModules());
54|        if (instructions != null && !instructions.isBlank()) all.add(new Module("custom-instructions", 80, instructions));
55|        if (memory != null && !memory.isBlank()) all.add(new Module("long-term-memory", 100, memory));
56|        return assemble(all);
57|    }
