58|    private static String callLlm(LlmProvider provider, String prompt) throws Exception {
59|        var msgs = List.of(new MessageRecord(Role.USER, prompt));
60|        var req = new Request(msgs, List.of(), new System("你是记忆提取助手。只输出 JSON，禁止调用工具。", ""), "");
61|        CompletableFuture<String> future = new CompletableFuture<>();
62|        provider.chatStream(req, new StreamHandler() {
63|            final StringBuilder text = new StringBuilder();
64|            @Override public void onToken(String t) { text.append(t); }
65|            @Override public void onComplete() { future.complete(text.toString().trim()); }
66|            @Override public void onError(Exception e) { future.completeExceptionally(e); }
67|            @Override public void onUsage(int i, int o, int cw, int cr) {}
68|        });
