72|    private static void applyOperations(String response, MemoryStore proj, MemoryStore user) {
73|        try {
74|            String cleaned = extractJson(response);
75|            if (cleaned.isEmpty()) {
76|                java.lang.System.err.println("[memory] no JSON found in response, raw: " + response.substring(0, Math.min(200, response.length())));
77|                return;
78|            }
79|            JsonNode arr = json.readTree(cleaned);
80|            if (!arr.isArray()) return;
81|            for (JsonNode op : arr) {
82|                String action = op.path("action").asText();
83|                String level = op.path("level").asText("project");
84|                MemoryStore store = "user".equals(level) ? user : proj;
85|                try {
86|                    switch (action) {
87|                        case "create" -> store.create(
88|                            op.path("type").asText(), op.path("slug").asText(),
89|                            op.path("title").asText(), op.path("content").asText());
90|                        case "update" -> store.update(
91|                            op.path("filename").asText(), op.path("title").asText(null),
92|                            op.path("content").asText(null));
93|                        case "delete" -> store.delete(op.path("filename").asText());
94|                    }
95|                } catch (Exception e) {
96|                    java.lang.System.err.println("[memory] op failed: " + e.getMessage());
97|                }
98|            }
99|        } catch (Exception e) {
100|            java.lang.System.err.println("[memory] parse failed: " + e.getMessage());
101|        }
102|    }
