104|    /** 从 LLM 响应中提取 JSON：去除 markdown 代码块和前后文字 */
105|    private static String extractJson(String raw) {
106|        String s = raw.trim();
107|        if (s.startsWith("```")) {
108|            int start = s.indexOf('\n');
109|            int end = s.lastIndexOf("```");
110|            if (start > 0 && end > start) s = s.substring(start + 1, end).trim();
111|        }
112|        int arrStart = s.indexOf('[');
113|        int arrEnd = s.lastIndexOf(']');
114|        if (arrStart >= 0 && arrEnd > arrStart) return s.substring(arrStart, arrEnd + 1);
115|        int objStart = s.indexOf('{');
116|        int objEnd = s.lastIndexOf('}');
117|        if (objStart >= 0 && objEnd > objStart) return s.substring(objStart, objEnd + 1);
118|        return "";
119|    }
