21|            sb.append("## 用户笔记\n\n").append(ui);
22|        }
23|        String result = sb.toString().trim();
24|        byte[] bytes = result.getBytes(java.nio.charset.StandardCharsets.UTF_8);
25|        if (bytes.length > MAX_INDEX_BYTES) {
26|            String truncated = new String(bytes, 0, MAX_INDEX_BYTES, java.nio.charset.StandardCharsets.UTF_8);
27|            // 避免截断在多字节字符中间
28|            int lastValid = truncated.length() - 1;
29|            while (lastValid >= 0 && Character.isSurrogate(truncated.charAt(lastValid))) lastValid--;
