12|/** 笔记文件 CRUD + 索引管理（F27-F31）。线程安全。 */
13|public final class MemoryStore {
14|    private static final DateTimeFormatter ISO = DateTimeFormatter.ISO_OFFSET_DATE_TIME;
15|    private final Path memoryDir;
16|
17|    public MemoryStore(Path memoryDir) {
18|        this.memoryDir = memoryDir;
19|        ensureDir();
20|    }
21|
22|    private void ensureDir() {
23|        try { Files.createDirectories(memoryDir); } catch (IOException ignored) {}
24|    }
25|
26|    /** F28/F31: 创建笔记 */
27|    public synchronized void create(String type, String slug, String title, String content) throws IOException {
28|        String now = ZonedDateTime.now().format(ISO);
29|        String md = "---\ntype: " + type + "\ntitle: " + title + "\ncreated: " + now + "\nupdated: " + now + "\n---\n\n" + content + "\n";
30|        Path file = memoryDir.resolve(type + "_" + slug + ".md");
31|        Path tmp = memoryDir.resolve("." + file.getFileName() + ".tmp");
32|        Files.writeString(tmp, md, StandardCharsets.UTF_8);
33|        Files.move(tmp, file, java.nio.file.StandardCopyOption.ATOMIC_MOVE, java.nio.file.StandardCopyOption.REPLACE_EXISTING);
34|        appendIndex("- [" + type + "] " + title + " — " + truncateDesc(content));
35|    }
36|
37|    /** 更新笔记 */
38|    public synchronized void update(String filename, String title, String content) throws IOException {
39|        Path file = memoryDir.resolve(filename);
40|        if (!Files.isRegularFile(file)) return;
41|        String old = Files.readString(file, StandardCharsets.UTF_8);
42|        String now = ZonedDateTime.now().format(ISO);
43|        // 更新 frontmatter 中的 updated 字段
44|        String updated = old.replaceFirst("updated: .*", "updated: " + now);
45|        // 更新 title（如果改了）
46|        if (title != null && !title.isBlank()) {
47|            updated = updated.replaceFirst("title: .*", "title: " + title);
48|        }
49|        // 更新 body（frontmatter 之后的内容）
50|        if (content != null && !content.isBlank()) {
51|            int bodyStart = updated.indexOf("---\n", 4);
52|            if (bodyStart >= 0) {
53|                updated = updated.substring(0, bodyStart + 4) + "\n\n" + content + "\n";
54|            }
55|        }
56|        Path tmp = memoryDir.resolve("." + filename + ".tmp");
57|        Files.writeString(tmp, updated, StandardCharsets.UTF_8);
58|        Files.move(tmp, file, java.nio.file.StandardCopyOption.ATOMIC_MOVE, java.nio.file.StandardCopyOption.REPLACE_EXISTING);
59|        updateIndexLine(filename, title, content);
60|    }
61|
62|    /** 删除笔记 */
63|    public synchronized void delete(String filename) throws IOException {
64|        Path file = memoryDir.resolve(filename);
65|        Files.deleteIfExists(file);
66|        removeIndexLine(filename);
67|    }
68|
69|    /** 读取索引（F30） */
70|    public synchronized String readIndex() {
71|        Path idx = memoryDir.resolve("MEMORY.md");
72|        if (!Files.isRegularFile(idx)) return "";
73|        try {
74|            return Files.readString(idx, StandardCharsets.UTF_8).trim();
75|        } catch (IOException e) {
76|            return "";
77|        }
78|    }
79|
80|    // ---- 索引操作 ----
81|
82|    private Path indexFile() { return memoryDir.resolve("MEMORY.md"); }
83|
84|    private void appendIndex(String line) throws IOException {
85|        Path idx = indexFile();
86|        String existing = Files.isRegularFile(idx) ? Files.readString(idx, StandardCharsets.UTF_8) : "";
87|        Files.writeString(idx, (existing.isEmpty() ? "" : existing + "\n") + line, StandardCharsets.UTF_8);
88|    }
89|
90|    private void updateIndexLine(String filename, String title, String content) throws IOException {
91|        Path idx = indexFile();
92|        if (!Files.isRegularFile(idx)) return;
93|        List<String> lines = new ArrayList<>(Files.readAllLines(idx, StandardCharsets.UTF_8));
94|        for (int i = 0; i < lines.size(); i++) {
95|            if (lines.get(i).contains(filename)) {
96|                String newLine = "- [";
97|                // 从原行提取 type
98|                int t1 = lines.get(i).indexOf('[');
99|                int t2 = lines.get(i).indexOf(']', t1);
100|                String type = t1 >= 0 && t2 > t1 ? lines.get(i).substring(t1 + 1, t2) : "?";
101|                newLine += type + "] " + (title != null ? title : "") + " — " + truncateDesc(content);
102|                lines.set(i, newLine);
103|                break;
104|            }
105|        }
106|        Files.write(idx, lines, StandardCharsets.UTF_8);
107|    }
108|
109|    private void removeIndexLine(String filename) throws IOException {
110|        Path idx = indexFile();
111|        if (!Files.isRegularFile(idx)) return;
112|        List<String> lines = new ArrayList<>(Files.readAllLines(idx, StandardCharsets.UTF_8));
113|        lines.removeIf(l -> l.contains(filename));
114|        Files.write(idx, lines, StandardCharsets.UTF_8);
115|    }
116|
117|    private static String truncateDesc(String content) {
118|        if (content == null || content.isBlank()) return "";
119|        String s = content.replace('\n', ' ').trim();
120|        return s.length() > 80 ? s.substring(0, 77) + "..." : s;
121|    }
