113|            if (collector.hasError()) {
114|                eventSink.accept(new AgentEvent.Error(collector.getErrorMessage(), false));
115|                eventSink.accept(new AgentEvent.AgentFinished(null, round, totalInputTokens, totalOutputTokens));
