121|            totalInputTokens += roundIn;
122|            totalOutputTokens += roundOut;
123|            eventSink.accept(new AgentEvent.TokenUsage(roundIn, roundOut, totalInputTokens, totalOutputTokens,
124|                    collector.getCacheWriteTokens(), collector.getCacheReadTokens()));
