134|            if (toolCalls.isEmpty() && !thinkingText.isBlank()) {
135|                emptyTextRetries = 0;
136|                conversation.addAssistantMessage(thinkingText);
137|                eventSink.accept(new AgentEvent.AgentFinished(thinkingText, round, totalInputTokens, totalOutputTokens));
