82|    /** ch08: 结合 ReplacementLedger 组装消息列表 */
83|    public List<MessageRecord> assembleMessages(ReplacementLedger ledger) {
84|        List<MessageRecord> result = new ArrayList<>();
85|        for (MessageRecord msg : getHistory()) {
86|            List<MessageBlock> newBlocks = new ArrayList<>();
87|            boolean changed = false;
88|            for (MessageBlock b : msg.blocks()) {
89|                if (b instanceof MessageBlock.ToolResultBlock tr) {
90|                    String replacement = ledger.getReplacement(tr.toolUseId());
91|                    if (replacement != null) {
92|                        newBlocks.add(new MessageBlock.ToolResultBlock(tr.toolUseId(), replacement, tr.isError()));
93|                        changed = true;
94|                    } else { newBlocks.add(b); }
95|                } else { newBlocks.add(b); }
96|            }
97|            result.add(changed ? new MessageRecord(msg.role(), msg.content(), newBlocks) : msg);
98|        }
99|        return result;
100|    }
101|
102|    /** 修复 role 交替违规——防止 USER→USER 连续导致 API 截断返回空文本 */
103|    public void fixRoleAlternation() {
104|        if (history.size() < 2) return;
105|        for (int i = 1; i < history.size(); i++) {
106|            Role prev = history.get(i - 1).role();
107|            Role curr = history.get(i).role();
108|            if (prev == Role.USER && curr == Role.USER) {
109|                // 合并两条连续 USER 消息，而非插入无意义的占位消息
110|                MessageRecord a = history.get(i - 1);
111|                MessageRecord b = history.get(i);
112|                String mergedContent = joinContent(a.content(), b.content());
113|                List<MessageBlock> mergedBlocks = new ArrayList<>(a.blocks());
114|                mergedBlocks.addAll(b.blocks());
115|                history.set(i - 1, new MessageRecord(Role.USER, mergedContent, mergedBlocks));
116|                history.remove(i);
117|                i--; // 重新检查当前位置
118|            } else if (prev == Role.ASSISTANT && curr == Role.ASSISTANT) {
119|                MessageRecord a = history.get(i - 1);
120|                MessageRecord b = history.get(i);
121|                String mergedContent = joinContent(a.content(), b.content());
122|                List<MessageBlock> mergedBlocks = new ArrayList<>(a.blocks());
123|                mergedBlocks.addAll(b.blocks());
124|                history.set(i - 1, new MessageRecord(Role.ASSISTANT, mergedContent, mergedBlocks));
125|                history.remove(i);
126|                i--;
127|            }
128|        }
129|    }
130|
131|    private static String joinContent(String a, String b) {
132|        if (a == null || a.isBlank()) return b != null ? b : "";
133|        if (b == null || b.isBlank()) return a;
134|        return a + "\n\n" + b;
135|    }
136|
137|    // ---- 估算与裁剪 ----
138|
139|    public int estimateTokens() {
140|        long totalChars = 0;
141|        for (MessageRecord m : history) {
142|            totalChars += m.content() != null ? m.content().length() : 0;
143|            for (MessageBlock b : m.blocks()) {
144|                if (b instanceof MessageBlock.TextBlock tb) totalChars += tb.text().length();
145|                else if (b instanceof MessageBlock.ToolResultBlock tr) totalChars += tr.content().length();
146|            }
147|        }
148|        return (int)(totalChars / 3);
149|    }
150|
151|    public void trimToWindow(int maxTokens) {
152|        if (history.isEmpty()) return;
153|        while (estimateTokens() > maxTokens && history.size() > 2) {
154|            int lastUser = history.size() - 1;
155|            while (lastUser > 0 && history.get(lastUser).role() != Role.USER) lastUser--;
156|            if (lastUser <= 0) break;
157|            for (int i = 1; i < history.size(); i++) {
158|                if (i != lastUser) { history.remove(i); break; }
159|            }
160|        }
161|    }
