45|    /** 从 session ID 中解析时间戳（用于排序/清理） */
46|    public static Optional<LocalDateTime> parseTimestamp(String sessionId) {
47|        var m = ID_PATTERN.matcher(sessionId);
48|        if (!m.matches()) return Optional.empty();
49|        try {
50|            return Optional.of(LocalDateTime.parse(m.group(1), FMT));
51|        } catch (Exception e) {
52|            return Optional.empty();
53|        }
54|    }
